framework_css:
:root {
  --color-primary-red: #D71920;
  --color-primary-blue: #0055A4;
  --color-secondary-green: #00A859;
  --color-secondary-yellow: #FFB81C;
  --color-bg: #FFFFFF;
  --color-bg-muted: #F5F7FA;
  --color-text: #333333;
  --color-surface: #FFFFFF;
  --shadow-soft: 0 2px 6px rgba(0, 0, 0, 0.06);
  --radius-pill: 999px;
  --radius-card: 8px;

  --font-heading: 'Space Grotesk', Helvetica, sans-serif;
  --font-body: 'Source Sans 3', Arial, sans-serif;

  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  font-size: 16px;
}

body {
  margin: 0;
  font-family: var(--font-body);
  color: var(--color-text);
  background-color: var(--color-bg);
  line-height: 1.5;
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: inherit;
}

/* Header */

.site-header {
  position: sticky;
  top: 0;
  z-index: 100;
  background-color: var(--color-surface);
  box-shadow: var(--shadow-soft);
}

.header-inner {
  max-width: 1200px;
  margin: 0 auto;
  padding: var(--space-3) var(--space-4);
  display: flex;
  align-items: center;
  gap: var(--space-4);
}

.brand {
  display: flex;
  align-items: center;
  gap: var(--space-2);
  text-decoration: none;
  color: var(--color-text);
  flex-shrink: 0;
}

.brand-mark {
  width: 60px;
  height: 60px;
  border-radius: 50%;
  background-color: var(--color-primary-red);
  display: flex;
  align-items: center;
  justify-content: center;
}

.brand-mark-text {
  font-family: var(--font-heading);
  font-weight: 700;
  font-size: 1.5rem;
  letter-spacing: 0.06em;
  color: #FFFFFF;
}

.brand-text {
  display: flex;
  flex-direction: column;
  line-height: 1.1;
}

.brand-text-line {
  font-family: var(--font-heading);
  font-weight: 600;
  font-size: 0.8rem;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: var(--color-primary-blue);
}

.brand-text-line-secondary {
  font-weight: 500;
}

.primary-nav {
  flex: 1 1 auto;
}

.primary-nav-list {
  list-style: none;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-3);
  margin: 0;
  padding: 0;
  flex-wrap: wrap;
}

.primary-nav-item {
  position: relative;
}

.nav-link {
  font-family: var(--font-body);
  font-weight: 600;
  font-size: 0.98rem;
  color: var(--color-primary-blue);
  text-decoration: none;
  padding-bottom: 6px;
  border-bottom: 2px solid transparent;
  transition: color 0.18s ease, border-color 0.18s ease;
  white-space: nowrap;
}

.nav-link-accent {
  color: var(--color-primary-red);
}

.nav-link:hover,
.nav-link:focus-visible {
  color: var(--color-primary-red);
  border-bottom-color: var(--color-primary-red);
  outline: none;
}

.header-search-pill {
  flex-shrink: 0;
  min-width: 230px;
  border-radius: var(--radius-pill);
  border: 1px solid var(--color-primary-blue);
  padding: 10px 16px 10px 20px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  font-size: 0.9rem;
  color: #777777;
  background-color: #FFFFFF;
}

.search-label {
  opacity: 0.9;
}

.search-icon {
  width: 20px;
  height: 20px;
  border-radius: 50%;
  border: 2px solid var(--color-primary-red);
  display: inline-block;
  position: relative;
  box-sizing: border-box;
}

.search-icon::after {
  content: '';
  position: absolute;
  width: 9px;
  height: 2px;
  border-radius: 1px;
  background-color: var(--color-primary-red);
  right: -4px;
  bottom: 2px;
  transform: rotate(45deg);
  transform-origin: left center;
}

/* Main content wrapper */

.site-main {
  max-width: 1200px;
  margin: 0 auto;
  padding: var(--space-5) var(--space-4) var(--space-6);
  min-height: 50vh;
}

/* Footer */

.site-footer {
  background-color: var(--color-primary-blue);
  color: #FFFFFF;
  padding: var(--space-5) var(--space-4) var(--space-4);
  margin-top: auto;
}

.footer-inner {
  max-width: 1200px;
  margin: 0 auto;
  display: flex;
  flex-wrap: wrap;
  align-items: flex-start;
  justify-content: space-between;
  gap: var(--space-4);
}

.footer-brand {
  display: flex;
  align-items: center;
  gap: var(--space-2);
  flex: 0 0 auto;
}

.footer-brand-mark {
  width: 44px;
  height: 44px;
  border-radius: 50%;
  background-color: var(--color-primary-red);
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font-heading);
  font-weight: 700;
  font-size: 1.1rem;
  letter-spacing: 0.08em;
}

.footer-brand-text {
  display: flex;
  flex-direction: column;
}

.footer-brand-title {
  font-family: var(--font-heading);
  font-weight: 600;
  font-size: 0.95rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.footer-brand-subtitle {
  font-size: 0.85rem;
  opacity: 0.9;
}

.footer-nav {
  flex: 1 1 320px;
}

.footer-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));
  gap: var(--space-2) var(--space-4);
}

.footer-link {
  display: inline-block;
  font-size: 0.9rem;
  text-decoration: none;
  color: #FFFFFF;
  opacity: 0.9;
  padding-bottom: 4px;
  border-bottom: 1px solid transparent;
  transition: opacity 0.18s ease, border-color 0.18s ease;
}

.footer-link:hover,
.footer-link:focus-visible {
  opacity: 1;
  border-bottom-color: rgba(255, 255, 255, 0.9);
  outline: none;
}

.footer-bottom {
  max-width: 1200px;
  margin: var(--space-4) auto 0;
  padding-top: var(--space-3);
  border-top: 1px solid rgba(255, 255, 255, 0.25);
  display: flex;
  flex-wrap: wrap;
  justify-content: space-between;
  gap: var(--space-2);
  font-size: 0.78rem;
  opacity: 0.9;
}

.footer-meta {
  margin: 0;
}

/* Responsive adjustments */

@media (max-width: 960px) {
  .header-inner {
    flex-wrap: wrap;
    align-items: flex-start;
    gap: var(--space-3);
  }

  .primary-nav {
    order: 3;
    width: 100%;
  }

  .primary-nav-list {
    justify-content: flex-start;
    column-gap: var(--space-3);
    row-gap: var(--space-1);
  }

  .header-search-pill {
    order: 2;
    align-self: flex-start;
  }
}

@media (max-width: 640px) {
  .header-inner {
    padding-inline: var(--space-3);
  }

  .site-main {
    padding-inline: var(--space-3);
  }

  .site-footer {
    padding-inline: var(--space-3);
  }
}
